     1â†’"use client";
     2â†’
     3â†’import { usePathname } from "next/navigation";
     4â†’
     5â†’const SEGMENT_LABELS: Record<string, string> = {
     6â†’  "": "Dashboard",
     7â†’  projects: "Projects",
     8â†’  releases: "Releases",
     9â†’  sources: "Sources",
    10â†’  subscriptions: "Subscriptions",
    11â†’  channels: "Channels",
    12â†’  agent: "Agent",
    13â†’  "semantic-releases": "Semantic Releases",
    14â†’  "context-sources": "Context Sources",
    15â†’  new: "New",
    16â†’  edit: "Edit",
    17â†’};
    18â†’
    19â†’function segmentLabel(seg: string): string {
    20â†’  return SEGMENT_LABELS[seg] ?? seg;
    21â†’}
    22â†’
    23â†’export function Header() {
    24â†’  const pathname = usePathname();
    25â†’  const segments = pathname.split("/").filter(Boolean);
    26â†’
    27â†’  const uuidRe = /^[0-9a-f-]{8,}$/i;
    28â†’  const breadcrumbs = segments
    29â†’    .filter((s) => !uuidRe.test(s))
    30â†’    .map(segmentLabel);
    31â†’
    32â†’  const display =
    33â†’    breadcrumbs.length === 0
    34â†’      ? "Dashboard"
    35â†’      : breadcrumbs.join(" / ");
    36â†’
    37â†’  return (
    38â†’    <header
    39â†’      className="flex h-12 items-center px-6"
    40â†’      style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
    41â†’    >
    42â†’      <p
    43â†’        className="text-[14px] font-medium text-[#111113]"
    44â†’        style={{ fontFamily: "var(--font-dm-sans)" }}
    45â†’      >
    46â†’        {display}
    47â†’      </p>
    48â†’    </header>
    49â†’  );
    50â†’}
