     1â†’"use client";
     2â†’
     3â†’import Link from "next/link";
     4â†’import { usePathname } from "next/navigation";
     5â†’import {
     6â†’  LayoutDashboard,
     7â†’  FolderKanban,
     8â†’  Package,
     9â†’  Bell,
    10â†’  Megaphone,
    11â†’} from "lucide-react";
