     2â†’"use client";
     3â†’
     4â†’import useSWR from "swr";
     5â†’import Link from "next/link";
     6â†’import { StatsCards } from "@/components/dashboard/stats-cards";
     7â†’import { RecentReleases } from "@/components/dashboard/recent-releases";
     8â†’import {
     9â†’  projects as projectsApi,
    10â†’  semanticReleases as srApi,
    11â†’} from "@/lib/api/client";
    12â†’import { StatusDot } from "@/components/ui/status-dot";
    13â†’import { VersionChip } from "@/components/ui/version-chip";
    14â†’import type { SemanticRelease } from "@/lib/api/types";
    15â†’import { timeAgo } from "@/lib/format";
    16â†’
    17â†’interface SRRow extends SemanticRelease {
    18â†’  _projectName?: string;
    19â†’}
    20â†’
    21â†’function SemanticReleasesColumn() {
    22â†’  const { data: projectsData } = useSWR("projects-for-sr-dashboard", () =>
    23â†’    projectsApi.list()
    24â†’  );
    25â†’
    26â†’  const { data: allSRs, isLoading } = useSWR(
    27â†’    projectsData ? "recent-semantic-releases" : null,
    28â†’    async () => {
    29â†’      if (!projectsData?.data?.length) return [];
    30â†’
    31â†’      const projectMap = new Map(
    32â†’        projectsData.data.map((p) => [p.id, p.name])
    33â†’      );
    34â†’
    35â†’      const results = await Promise.all(
    36â†’        projectsData.data.slice(0, 10).map((p) =>
    37â†’          srApi.list(p.id, 1).catch(() => null)
    38â†’        )
    39â†’      );
    40â†’
    41â†’      const srs: SRRow[] = results
    42â†’        .filter((r): r is NonNullable<typeof r> => r !== null)
    43â†’        .flatMap((r) => r.data)
    44â†’        .sort(
    45â†’          (a, b) =>
    46â†’            new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
    47â†’        )
    48â†’        .slice(0, 6)
    49â†’        .map((sr) => ({
    50â†’          ...sr,
    51â†’          _projectName: projectMap.get(sr.project_id),
    52â†’        }));
    53â†’
    54â†’      return srs;
    55â†’    }
    56â†’  );
    57â†’
    58â†’  return (
    59â†’    <div
    60â†’      className="rounded-lg bg-white"
    61â†’      style={{ border: "1px solid #e8e8e5" }}
    62â†’    >
    63â†’      {/* Header */}
    64â†’      <div
    65â†’        className="flex items-center justify-between px-5 py-4"
    66â†’        style={{ borderBottom: "1px solid #e8e8e5" }}
    67â†’      >
    68â†’        <h3
    69â†’          className="font-medium"
    70â†’          style={{
    71â†’            fontFamily: "var(--font-dm-sans)",
    72â†’            fontSize: "13px",
    73â†’            color: "#111113",
    74â†’          }}
    75â†’        >
    76â†’          Semantic Releases
    77â†’        </h3>
    78â†’        <Link
    79â†’          href="/projects"
    80â†’          className="text-sm hover:underline"
    81â†’          style={{
    82â†’            fontFamily: "var(--font-dm-sans)",
    83â†’            fontSize: "13px",
    84â†’            color: "#e8601a",
    85â†’          }}
    86â†’        >
    87â†’          View all &rarr;
    88â†’        </Link>
    89â†’      </div>
    90â†’
    91â†’      {/* Body */}
    92â†’      <div className="p-4 space-y-3">
    93â†’        {isLoading ? (
    94â†’          <div
    95â†’            className="py-8 text-center"
    96â†’            style={{
    97â†’              fontFamily: "var(--font-dm-sans)",
    98â†’              fontSize: "13px",
    99â†’              color: "#6b7280",
   100â†’            }}
   101â†’          >
   102â†’            Loading...
   103â†’          </div>
   104â†’        ) : allSRs && allSRs.length > 0 ? (
   105â†’          allSRs.map((sr: SRRow) => (
   106â†’            <Link
   107â†’              key={sr.id}
   108â†’              href={`/projects/${sr.project_id}/semantic-releases/${sr.id}`}
   109â†’              className="block rounded-lg px-4 py-3 transition-colors hover:bg-[#fafaf9]"
   110â†’              style={{ border: "1px solid #e8e8e5" }}
   111â†’            >
   112â†’              <div className="flex items-center justify-between">
   113â†’                <span
   114â†’                  className="font-semibold"
   115â†’                  style={{
   116â†’                    fontFamily: "var(--font-fraunces)",
   117â†’                    fontSize: "15px",
   118â†’                    color: "#111113",
   119â†’                  }}
   120â†’                >
   121â†’                  {sr._projectName ?? "Unknown Project"}
   122â†’                </span>
   123â†’                <VersionChip version={sr.version} />
   124â†’              </div>
   125â†’              {sr.report?.summary && (
   126â†’                <p
   127â†’                  className="mt-1 line-clamp-1"
   128â†’                  style={{
   129â†’                    fontFamily: "var(--font-dm-sans)",
   130â†’                    fontStyle: "italic",
   131â†’                    fontSize: "13px",
   132â†’                    color: "#6b7280",
   133â†’                  }}
   134â†’                >
   135â†’                  {sr.report.summary}
   136â†’                </p>
   137â†’              )}
   138â†’              <div className="mt-2 flex items-center gap-2">
   139â†’                <StatusDot status={sr.status} />
   140â†’                <span
   141â†’                  style={{
   142â†’                    fontFamily: "var(--font-dm-sans)",
   143â†’                    fontSize: "12px",
   144â†’                    color: "#9ca3af",
   145â†’                  }}
   146â†’                >
   147â†’                  {timeAgo(sr.created_at)}
   148â†’                </span>
   149â†’              </div>
   150â†’            </Link>
   151â†’          ))
   152â†’        ) : (
   153â†’          <div className="py-8 text-center">
   154â†’            <p
   155â†’              style={{
   156â†’                fontFamily: "var(--font-fraunces)",
   157â†’                fontStyle: "italic",
   158â†’                fontSize: "14px",
   159â†’                color: "#9ca3af",
   160â†’              }}
   161â†’            >
   162â†’              No semantic releases yet
   163â†’            </p>
   164â†’          </div>
   165â†’        )}
   166â†’      </div>
   167â†’    </div>
   168â†’  );
   169â†’}
   170â†’
   171â†’export default function DashboardPage() {
   172â†’  return (
   173â†’    <div className="space-y-6">
   174â†’      <StatsCards />
   175â†’      <div className="grid gap-6 lg:grid-cols-2">
   176â†’        <RecentReleases />
   177â†’        <SemanticReleasesColumn />
   178â†’      </div>
   179â†’    </div>
   180â†’  );
   181â†’}
