     3â†’import { useState } from "react";
     4â†’import useSWR from "swr";
     5â†’import Link from "next/link";
     6â†’import {
     7â†’  projects as projectsApi,
     8â†’  releases as releasesApi,
     9â†’  semanticReleases as srApi,
    10â†’  sources as sourcesApi,
    11â†’} from "@/lib/api/client";
    12â†’import { getProviderIcon } from "@/components/ui/provider-badge";
    13â†’import { timeAgo } from "@/lib/format";
    14â†’import { Plus } from "lucide-react";
    15â†’import type { Project } from "@/lib/api/types";
    16â†’
    17â†’const CHUNK_SIZE = 3;
    18â†’
    19â†’function ReleaseChips({ projectId }: { projectId: string }) {
    20â†’  const [limit, setLimit] = useState(CHUNK_SIZE);
    21â†’  const { data } = useSWR(
    22â†’    `projects/${projectId}/releases?limit=${limit + 1}`,
    23â†’    () => releasesApi.listByProject(projectId, 1, limit + 1)
    24â†’  );
    25â†’  const { data: sourcesData } = useSWR(
    26â†’    `projects/${projectId}/sources`,
    27â†’    () => sourcesApi.listByProject(projectId)
    28â†’  );
    29â†’  const items = data?.data ?? [];
    30â†’  const hasMore = items.length > limit;
    31â†’  const shown = items.slice(0, limit);
    32â†’
    33â†’  const providerMap = new Map<string, string>();
    34â†’  for (const s of sourcesData?.data ?? []) {
    35â†’    providerMap.set(s.id, s.provider);
    36â†’  }
    37â†’
    38â†’  if (!data) return <span className="text-[12px] text-[#c4c4c0] italic">loadingâ€¦</span>;
    39â†’  if (shown.length === 0) return <span className="text-[12px] text-[#c4c4c0]">â€”</span>;
    40â†’
    41â†’  return (
    42â†’    <div className="flex flex-wrap items-center gap-1">
    43â†’      {shown.map((r) => {
    44â†’        const provider = providerMap.get(r.source_id);
    45â†’        const Icon = provider ? getProviderIcon(provider) : undefined;
    46â†’        return (
    47â†’          <Link
    48â†’            key={r.id}
    49â†’            href={`/releases/${r.id}`}
    50â†’            className="inline-flex items-center gap-1 rounded px-1.5 py-0.5 text-[12px] leading-none text-[#374151] transition-colors hover:bg-[#e8e8e5]"
    51â†’            style={{ backgroundColor: "#f3f3f1", fontFamily: "'JetBrains Mono', monospace" }}
    52â†’          >
    53â†’            {Icon && <Icon size={11} className="shrink-0 text-[#6b7280]" />}
    54â†’            {r.version}
    55â†’          </Link>
    56â†’        );
    57â†’      })}
    58â†’      {hasMore && (
    59â†’        <button
    60â†’          onClick={() => setLimit((n) => n + CHUNK_SIZE)}
    61â†’          className="text-[11px] text-[#e8601a] hover:underline"
    62â†’          style={{ fontFamily: "var(--font-dm-sans)" }}
    63â†’        >
    64â†’          moreâ€¦
    65â†’        </button>
    66â†’      )}
    67â†’    </div>
    68â†’  );
    69â†’}
    70â†’
    71â†’function SemanticReleaseChips({ projectId }: { projectId: string }) {
    72â†’  const [limit, setLimit] = useState(CHUNK_SIZE);
    73â†’  const { data } = useSWR(
    74â†’    `projects/${projectId}/sr?limit=${limit + 1}`,
    75â†’    () => srApi.list(projectId, 1, limit + 1)
    76â†’  );
    77â†’  const items = data?.data ?? [];
    78â†’  const hasMore = items.length > limit;
    79â†’  const shown = items.slice(0, limit);
    80â†’
    81â†’  if (!data) return <span className="text-[12px] text-[#c4c4c0] italic">loadingâ€¦</span>;
    82â†’  if (shown.length === 0) return <span className="text-[12px] text-[#c4c4c0]">â€”</span>;
    83â†’
    84â†’  return (
    85â†’    <div className="flex flex-wrap items-center gap-1">
    86â†’      {shown.map((sr) => (
    87â†’        <Link
    88â†’          key={sr.id}
    89â†’          href={`/projects/${projectId}/semantic-releases/${sr.id}`}
    90â†’          className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none text-[#1d4ed8] transition-colors hover:bg-[#dbeafe]"
    91â†’          style={{ backgroundColor: "#eff6ff", fontFamily: "'JetBrains Mono', monospace" }}
    92â†’        >
    93â†’          {sr.version}
    94â†’        </Link>
    95â†’      ))}
    96â†’      {hasMore && (
    97â†’        <button
    98â†’          onClick={() => setLimit((n) => n + CHUNK_SIZE)}
    99â†’          className="text-[11px] text-[#e8601a] hover:underline"
   100â†’          style={{ fontFamily: "var(--font-dm-sans)" }}
   101â†’        >
   102â†’          moreâ€¦
   103â†’        </button>
   104â†’      )}
   105â†’    </div>
   106â†’  );
   107â†’}
