   121â†’        </Link>
   122â†’      </td>
   123â†’      <td className="max-w-[220px] truncate px-4 py-2.5 text-[#6b7280]">
   124â†’        {project.description || "â€”"}
   125â†’      </td>
   126â†’      <td className="px-4 py-2.5">
   127â†’        <ReleaseChips projectId={project.id} />
   128â†’      </td>
   129â†’      <td className="px-4 py-2.5">
