   134â†’      </td>
   135â†’    </tr>
   136â†’  );
   137â†’}
   138â†’
   139â†’export default function ProjectsPage() {
   140â†’  const { data, isLoading } = useSWR("projects", () => projectsApi.list());
   141â†’  const items = data?.data ?? [];
   142â†’
   143â†’  return (
   144â†’    <div className="flex flex-col gap-4 fade-in">
   145â†’      <div className="flex items-center justify-between">
   146â†’        <div>
   147â†’          <h1
   148â†’            className="text-[24px] font-semibold text-[#111113]"
   149â†’            style={{ fontFamily: "var(--font-fraunces)" }}
   150â†’          >
   151â†’            Projects
   152â†’          </h1>
   153â†’          <p
   154â†’            className="mt-1 text-[13px] text-[#6b7280]"
   155â†’            style={{ fontFamily: "var(--font-dm-sans)" }}
   156â†’          >
   157â†’            Tracked software projects and their recent releases.
   158â†’          </p>
