    95â†’        <Link
    96â†’          href="/releases"
    97â†’          className="text-sm hover:underline"
    98â†’          style={{
    99â†’            fontFamily: "var(--font-dm-sans)",
   100â†’            fontSize: "13px",
   101â†’            color: "#e8601a",
   102â†’          }}
   103â†’        >
   104â†’          View all &rarr;
   105â†’        </Link>
   106â†’      </div>
   107â†’
   108â†’      {/* Body */}
   109â†’      <div>
   110â†’        {isLoading ? (
   111â†’          <div
   112â†’            className="py-12 text-center"
   113â†’            style={{
   114â†’              fontFamily: "var(--font-dm-sans)",
   115â†’              fontSize: "13px",
   116â†’              color: "#6b7280",
   117â†’            }}
   118â†’          >
   119â†’            Loading...
   120â†’          </div>
   121â†’        ) : allReleases && allReleases.length > 0 ? (
   122â†’          allReleases.map((release: ReleaseRow, idx: number) => {
   123â†’            const Icon = release._provider ? getProviderIcon(release._provider) : undefined;
   124â†’            return (
   125â†’            <Link
   126â†’              key={release.id}
   127â†’              href={`/releases/${release.id}`}
   128â†’              className="flex items-center justify-between px-5 py-3 transition-colors hover:bg-[#fafaf9]"
   129â†’              style={
   130â†’                idx < allReleases.length - 1
   131â†’                  ? { borderBottom: "1px solid #e8e8e5" }
