     1â†’package api
     2â†’
     3â†’import (
     4â†’	"context"
     5â†’	"crypto/sha256"
     6â†’	"encoding/hex"
     7â†’	"fmt"
     8â†’
     9â†’	"github.com/jackc/pgx/v5"
    10â†’	"github.com/jackc/pgx/v5/pgxpool"
    11â†’	"github.com/riverqueue/river"
    12â†’	"github.com/sentioxyz/changelogue/internal/models"
    13â†’	"github.com/sentioxyz/changelogue/internal/queue"
    14â†’)
    15â†’
    16â†’// PgStore implements all store interfaces using a PostgreSQL connection pool.
    17â†’type PgStore struct {
    18â†’	pool  *pgxpool.Pool
    19â†’	river *river.Client[pgx.Tx]
    20â†’}
    21â†’
    22â†’// NewPgStore returns a new PgStore backed by the given connection pool and River client.
    23â†’// The river client may be nil if agent triggering is not needed.
    24â†’func NewPgStore(pool *pgxpool.Pool, riverClient *river.Client[pgx.Tx]) *PgStore {
    25â†’	return &PgStore{pool: pool, river: riverClient}
    26â†’}
    27â†’
    28â†’// --- ProjectsStore ---
    29â†’
    30â†’func (s *PgStore) ListProjects(ctx context.Context, page, perPage int) ([]models.Project, int, error) {
    31â†’	var total int
    32â†’	err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM projects`).Scan(&total)
    33â†’	if err != nil {
    34â†’		return nil, 0, fmt.Errorf("count projects: %w", err)
    35â†’	}
    36â†’	offset := (page - 1) * perPage
    37â†’	rows, err := s.pool.Query(ctx,
    38â†’		`SELECT id, name, COALESCE(description,''), COALESCE(agent_prompt,''),
    39â†’		        COALESCE(agent_rules,'{}'), created_at, updated_at
    40â†’		 FROM projects ORDER BY created_at DESC LIMIT $1 OFFSET $2`, perPage, offset)
    41â†’	if err != nil {
    42â†’		return nil, 0, fmt.Errorf("list projects: %w", err)
    43â†’	}
    44â†’	defer rows.Close()
    45â†’	var projects []models.Project
    46â†’	for rows.Next() {
    47â†’		var p models.Project
    48â†’		if err := rows.Scan(&p.ID, &p.Name, &p.Description, &p.AgentPrompt, &p.AgentRules, &p.CreatedAt, &p.UpdatedAt); err != nil {
    49â†’			return nil, 0, fmt.Errorf("scan project: %w", err)
    50â†’		}
    51â†’		projects = append(projects, p)
    52â†’	}
    53â†’	return projects, total, nil
    54â†’}
    55â†’
    56â†’func (s *PgStore) CreateProject(ctx context.Context, p *models.Project) error {
    57â†’	return s.pool.QueryRow(ctx,
    58â†’		`INSERT INTO projects (name, description, agent_prompt, agent_rules)
    59â†’		 VALUES ($1, $2, $3, $4)
    60â†’		 RETURNING id, created_at, updated_at`,
    61â†’		p.Name, p.Description, p.AgentPrompt, p.AgentRules,
    62â†’	).Scan(&p.ID, &p.CreatedAt, &p.UpdatedAt)
    63â†’}
    64â†’
    65â†’func (s *PgStore) GetProject(ctx context.Context, id string) (*models.Project, error) {
    66â†’	var p models.Project
    67â†’	err := s.pool.QueryRow(ctx,
    68â†’		`SELECT id, name, COALESCE(description,''), COALESCE(agent_prompt,''),
    69â†’		        COALESCE(agent_rules,'{}'), created_at, updated_at
    70â†’		 FROM projects WHERE id = $1`, id,
    71â†’	).Scan(&p.ID, &p.Name, &p.Description, &p.AgentPrompt, &p.AgentRules, &p.CreatedAt, &p.UpdatedAt)
    72â†’	if err != nil {
    73â†’		return nil, err
    74â†’	}
    75â†’	return &p, nil
    76â†’}
    77â†’
    78â†’func (s *PgStore) UpdateProject(ctx context.Context, id string, p *models.Project) error {
    79â†’	return s.pool.QueryRow(ctx,
    80â†’		`UPDATE projects SET name=$1, description=$2, agent_prompt=$3, agent_rules=$4, updated_at=NOW()
    81â†’		 WHERE id=$5 RETURNING updated_at`,
    82â†’		p.Name, p.Description, p.AgentPrompt, p.AgentRules, id,
    83â†’	).Scan(&p.UpdatedAt)
    84â†’}
    85â†’
    86â†’func (s *PgStore) DeleteProject(ctx context.Context, id string) error {
    87â†’	tag, err := s.pool.Exec(ctx, `DELETE FROM projects WHERE id = $1`, id)
    88â†’	if err != nil {
    89â†’		return err
    90â†’	}
    91â†’	if tag.RowsAffected() == 0 {
    92â†’		return fmt.Errorf("not found")
    93â†’	}
    94â†’	return nil
    95â†’}
    96â†’
    97â†’// --- KeyStore ---
    98â†’
    99â†’func (s *PgStore) ValidateKey(ctx context.Context, rawKey string) (bool, error) {
   100â†’	hash := sha256.Sum256([]byte(rawKey))
   101â†’	keyHash := hex.EncodeToString(hash[:])
   102â†’	var exists bool
   103â†’	err := s.pool.QueryRow(ctx,
   104â†’		`SELECT EXISTS(SELECT 1 FROM api_keys WHERE key_hash = $1)`, keyHash,
   105â†’	).Scan(&exists)
   106â†’	return exists, err
   107â†’}
   108â†’
   109â†’func (s *PgStore) TouchKeyUsage(ctx context.Context, rawKey string) {
   110â†’	hash := sha256.Sum256([]byte(rawKey))
   111â†’	keyHash := hex.EncodeToString(hash[:])
   112â†’	_, _ = s.pool.Exec(ctx, `UPDATE api_keys SET last_used_at = NOW() WHERE key_hash = $1`, keyHash)
   113â†’}
   114â†’
   115â†’// --- SourcesStore ---
   116â†’
   117â†’func (s *PgStore) ListSourcesByProject(ctx context.Context, projectID string, page, perPage int) ([]models.Source, int, error) {
   118â†’	var total int
   119â†’	err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM sources WHERE project_id = $1`, projectID).Scan(&total)
   120â†’	if err != nil {
   121â†’		return nil, 0, fmt.Errorf("count sources: %w", err)
   122â†’	}
   123â†’	offset := (page - 1) * perPage
   124â†’	rows, err := s.pool.Query(ctx,
