    34â†’function formatDuration(startedAt?: string, completedAt?: string): string {
    35â†’  if (!startedAt) return "--";
    36â†’  const start = new Date(startedAt).getTime();
    37â†’  const end = completedAt ? new Date(completedAt).getTime() : Date.now();
    38â†’  const secs = Math.round((end - start) / 1000);
    39â†’  if (secs < 60) return `${secs}s`;
    40â†’  const mins = Math.floor(secs / 60);
    41â†’  const rem = secs % 60;
    42â†’  return `${mins}m ${rem}s`;
    43â†’}
    44â†’
    45â†’function truncate(str: string, max: number): string {
    46â†’  return str.length > max ? str.slice(0, max) + "\u2026" : str;
    47â†’}
    48â†’
    49â†’function formatInterval(seconds: number): string {
    50â†’  if (seconds < 60) return `${seconds}s`;
    51â†’  if (seconds < 3600) return `${Math.round(seconds / 60)}m`;
    52â†’  return `${(seconds / 3600).toFixed(1)}h`;
    53â†’}
