   191â†’func (s *PgStore) ListReleasesBySource(ctx context.Context, sourceID string, page, perPage int) ([]models.Release, int, error) {
   192â†’	var total int
   193â†’	err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM releases WHERE source_id = $1`, sourceID).Scan(&total)
   194â†’	if err != nil {
   195â†’		return nil, 0, fmt.Errorf("count releases: %w", err)
   196â†’	}
   197â†’	offset := (page - 1) * perPage
   198â†’	rows, err := s.pool.Query(ctx,
   199â†’		`SELECT id, source_id, version, COALESCE(raw_data,'{}'), released_at, created_at
   200â†’		 FROM releases WHERE source_id = $1 ORDER BY created_at DESC LIMIT $2 OFFSET $3`, sourceID, perPage, offset)
   201â†’	if err != nil {
   202â†’		return nil, 0, fmt.Errorf("list releases by source: %w", err)
   203â†’	}
   204â†’	defer rows.Close()
   205â†’	var releases []models.Release
   206â†’	for rows.Next() {
