	}
	return &rel, nil
}

// EnqueueAgentRun creates an agent_run row and enqueues a River AgentJobArgs.
// This follows the transactional outbox pattern for zero-loss guarantee.
func (s *PgStore) EnqueueAgentRun(ctx context.Context, projectID, trigger string) error {
	tx, err := s.pool.Begin(ctx)
	if err != nil {
		return fmt.Errorf("begin tx: %w", err)
	}
	defer tx.Rollback(ctx)

	var runID string
	err = tx.QueryRow(ctx,
		`INSERT INTO agent_runs (project_id, trigger, status)
		 VALUES ($1, $2, 'pending')
		 RETURNING id`, projectID, trigger,
	).Scan(&runID)
	if err != nil {
		return fmt.Errorf("insert agent run: %w", err)
	}

	if s.river != nil {
		_, err = s.river.InsertTx(ctx, tx, queue.AgentJobArgs{
			AgentRunID: runID,
			ProjectID:  projectID,
		}, nil)
		if err != nil {
			return fmt.Errorf("enqueue agent job: %w", err)
		}
	}

	return tx.Commit(ctx)
}

// --- OrchestratorStore (agent layer) ---

// UpdateAgentRunStatus sets the status of an agent run and updates the
// started_at timestamp when transitioning to "running".
func (s *PgStore) UpdateAgentRunStatus(ctx context.Context, id, status string) error {
	var query string
	switch status {
	case "running":
		query = `UPDATE agent_runs SET status = $1, started_at = NOW() WHERE id = $2`
	case "completed":
		query = `UPDATE agent_runs SET status = $1, completed_at = NOW() WHERE id = $2`
	default:
		query = `UPDATE agent_runs SET status = $1 WHERE id = $2`
	}
	tag, err := s.pool.Exec(ctx, query, status, id)
	if err != nil {
		return fmt.Errorf("update agent run status: %w", err)
	}
	if tag.RowsAffected() == 0 {
		return fmt.Errorf("agent run not found: %s", id)
	}
	return nil
}

// CreateSemanticRelease inserts a semantic release and its source release links
// in a single transaction. The sr.ID field is populated on success.
func (s *PgStore) CreateSemanticRelease(ctx context.Context, sr *models.SemanticRelease, releaseIDs []string) error {
	tx, err := s.pool.Begin(ctx)
	if err != nil {
		return fmt.Errorf("begin tx: %w", err)
	}
	defer tx.Rollback(ctx)

	err = tx.QueryRow(ctx,
		`INSERT INTO semantic_releases (project_id, version, report, status, completed_at)
		 VALUES ($1, $2, $3, $4, $5)
		 RETURNING id, created_at`,
		sr.ProjectID, sr.Version, sr.Report, sr.Status, sr.CompletedAt,
	).Scan(&sr.ID, &sr.CreatedAt)
	if err != nil {
		return fmt.Errorf("insert semantic release: %w", err)
	}

	for _, relID := range releaseIDs {
		_, err = tx.Exec(ctx,
			`INSERT INTO semantic_release_sources (semantic_release_id, release_id)
			 VALUES ($1, $2) ON CONFLICT DO NOTHING`,
			sr.ID, relID,
		)
		if err != nil {
			return fmt.Errorf("insert semantic release source: %w", err)
		}
	}

	return tx.Commit(ctx)
}

// UpdateAgentRunResult sets the semantic_release_id for a completed agent run.
func (s *PgStore) UpdateAgentRunResult(ctx context.Context, id string, semanticReleaseID string) error {
	tag, err := s.pool.Exec(ctx,
		`UPDATE agent_runs SET semantic_release_id = $1 WHERE id = $2`,
		semanticReleaseID, id,
	)
	if err != nil {
		return fmt.Errorf("update agent run result: %w", err)
	}
	if tag.RowsAffected() == 0 {
		return fmt.Errorf("agent run not found: %s", id)
	}
	return nil
}

// ListProjectSubscriptions returns all project-level subscriptions for a given project.
func (s *PgStore) ListProjectSubscriptions(ctx context.Context, projectID string) ([]models.Subscription, error) {
	rows, err := s.pool.Query(ctx,
		`SELECT id, channel_id, type, source_id, project_id, COALESCE(version_filter,''), created_at
		 FROM subscriptions
		 WHERE type = 'project' AND project_id = $1`, projectID)
	if err != nil {
		return nil, fmt.Errorf("list project subscriptions: %w", err)
	}
	defer rows.Close()
	var subs []models.Subscription
	for rows.Next() {
		var sub models.Subscription
		if err := rows.Scan(&sub.ID, &sub.ChannelID, &sub.Type, &sub.SourceID,
			&sub.ProjectID, &sub.VersionFilter, &sub.CreatedAt); err != nil {
			return nil, fmt.Errorf("scan subscription: %w", err)
		}
		subs = append(subs, sub)
	}
	return subs, nil
}

// --- HealthChecker ---

func (s *PgStore) Ping(ctx context.Context) error {
	return s.pool.Ping(ctx)
}

func (s *PgStore) PingDB(ctx context.Context) error {
	return s.pool.Ping(ctx)
}

func (s *PgStore) GetStats(ctx context.Context) (*DashboardStats, error) {
	var stats DashboardStats
	if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM releases`).Scan(&stats.TotalReleases); err != nil {
		return nil, fmt.Errorf("count releases: %w", err)
	}
	if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM sources WHERE enabled = true`).Scan(&stats.ActiveSources); err != nil {
		return nil, fmt.Errorf("count active sources: %w", err)
	}
	if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM projects`).Scan(&stats.TotalProjects); err != nil {
		return nil, fmt.Errorf("count projects: %w", err)
	}
	if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM agent_runs WHERE status = 'pending'`).Scan(&stats.PendingAgentRuns); err != nil {
		return nil, fmt.Errorf("count pending agent runs: %w", err)
	}
	return &stats, nil
}

// web/components/dashboard/recent-releases.tsx
"use client";

import useSWR from "swr";
import Link from "next/link";
import {
  projects as projectsApi,
  releases as releasesApi,
  sources as sourcesApi,
} from "@/lib/api/client";
import { VersionChip } from "@/components/ui/version-chip";
import { getProviderIcon } from "@/components/ui/provider-badge";
import type { Release, Source } from "@/lib/api/types";
import { timeAgo } from "@/lib/format";

interface ReleaseRow extends Release {
  _repository?: string;
  _provider?: string;
}

export function RecentReleases() {
  const { data: projectsData } = useSWR("projects-for-dashboard", () =>
    projectsApi.list()
  );

  const { data: allReleases, isLoading } = useSWR(
    projectsData ? "recent-releases" : null,
    async () => {
      if (!projectsData?.data?.length) return [];

      // Fetch releases and sources in parallel per project
      const projectSlice = projectsData.data.slice(0, 10);
      const [releaseResults, sourceResults] = await Promise.all([
        Promise.all(
          projectSlice.map((p) =>
            releasesApi.listByProject(p.id, 1).catch(() => null)
          )
        ),
        Promise.all(
          projectSlice.map((p) =>
            sourcesApi.listByProject(p.id, 1).catch(() => null)
          )
        ),
      ]);

      // Build source_id -> repository and source_id -> provider maps
      const sourceMap = new Map<string, string>();
      const providerMap = new Map<string, string>();
      sourceResults
        .filter((r): r is NonNullable<typeof r> => r !== null)
        .flatMap((r) => r.data)
        .forEach((s: Source) => {
          sourceMap.set(s.id, s.repository);
          providerMap.set(s.id, s.provider);
        });

      const releases: ReleaseRow[] = releaseResults
        .filter((r): r is NonNullable<typeof r> => r !== null)
        .flatMap((r) => r.data)
        .sort(
          (a, b) =>
            new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
        )
        .slice(0, 8)
        .map((rel) => ({
          ...rel,
          _repository: sourceMap.get(rel.source_id),
          _provider: providerMap.get(rel.source_id),
        }));

      return releases;
    }
  );

  return (
    <div
      className="rounded-lg bg-white"
      style={{ border: "1px solid #e8e8e5" }}
    >
      {/* Header */}
      <div
        className="flex items-center justify-between px-5 py-4"
        style={{ borderBottom: "1px solid #e8e8e5" }}
      >
        <h3
          className="font-medium"
          style={{
            fontFamily: "var(--font-dm-sans)",
            fontSize: "13px",
            color: "#111113",
          }}
        >
          Recent Source Releases
        </h3>
        <Link
          href="/releases"
          className="text-sm hover:underline"
          style={{
            fontFamily: "var(--font-dm-sans)",
            fontSize: "13px",
            color: "#e8601a",
          }}
        >
          View all &rarr;
        </Link>
      </div>

      {/* Body */}
      <div>
        {isLoading ? (
          <div
            className="py-12 text-center"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "13px",
              color: "#6b7280",
            }}
          >
            Loading...
          </div>
        ) : allReleases && allReleases.length > 0 ? (
          allReleases.map((release: ReleaseRow, idx: number) => {
            const Icon = release._provider ? getProviderIcon(release._provider) : undefined;
            return (
            <Link
              key={release.id}
              href={`/releases/${release.id}`}
              className="flex items-center justify-between px-5 py-3 transition-colors hover:bg-[#fafaf9]"
              style={
                idx < allReleases.length - 1
                  ? { borderBottom: "1px solid #e8e8e5" }
                  : undefined
              }
            >
              <span
                className="flex min-w-0 flex-1 items-center gap-1.5 truncate"
                style={{
                  fontFamily: "'JetBrains Mono', monospace",
                  fontSize: "13px",
                  color: "#6b7280",
                }}
              >
                {Icon && <Icon size={13} className="shrink-0 text-[#9ca3af]" />}
                {release._repository ?? release.source_id.slice(0, 12)}
              </span>
              <div className="ml-3 flex items-center gap-3">
                <VersionChip version={release.version} />
                <span
                  className="whitespace-nowrap"
                  style={{
                    fontFamily: "var(--font-dm-sans)",
                    fontSize: "12px",
                    color: "#9ca3af",
                  }}
                >
                  {timeAgo(release.released_at ?? release.created_at)}
                </span>
              </div>
            </Link>
          );})
        ) : (
          <div className="py-12 text-center">
            <p
              style={{
                fontFamily: "var(--font-fraunces)",
                fontStyle: "italic",
                fontSize: "14px",
                color: "#9ca3af",
              }}
            >
              No releases yet
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import useSWR from "swr";
import Link from "next/link";
import {
  releases as releasesApi,
  projects as projectsApi,
  sources as sourcesApi,
} from "@/lib/api/client";
import { ProviderBadge } from "@/components/ui/provider-badge";
import { VersionChip } from "@/components/ui/version-chip";
import type { Release, Source, Project } from "@/lib/api/types";
import { ExternalLink } from "lucide-react";

import { timeAgo } from "@/lib/format";

interface ReleaseRow extends Release {
  _projectName?: string;
  _projectId?: string;
  _provider?: string;
  _repository?: string;
}

const PER_PAGE = 15;

function getProviderUrl(
  provider: string,
  repository: string,
  version: string
): string | null {
  switch (provider) {
    case "github":
      return `https://github.com/${repository}/releases/tag/${version}`;
    case "dockerhub":
      return `https://hub.docker.com/r/${repository}/tags?name=${encodeURIComponent(version)}`;
    default:
      return null;
  }
}

/* ------------------------------------------------------------------ */
/*  Page                                                               */
/* ------------------------------------------------------------------ */

export default function ReleasesPage() {
  const [page, setPage] = useState(1);
  const [projectFilter, setProjectFilter] = useState<string>("all");

  /* Fetch projects for the filter dropdown + source enrichment */
  const { data: projectsData } = useSWR("projects-for-filter", () =>
    projectsApi.list()
  );

  /* Build a map: sourceId -> { provider, repository, projectName, projectId } */
  const { data: sourceMap } = useSWR(
    projectsData ? "source-map-for-releases" : null,
    async () => {
      if (!projectsData?.data?.length) return new Map<string, { provider: string; repository: string; projectName: string; projectId: string }>();
      const map = new Map<string, { provider: string; repository: string; projectName: string; projectId: string }>();
      await Promise.all(
        projectsData.data.map(async (p: Project) => {
          const res = await sourcesApi.listByProject(p.id).catch(() => null);
          if (res?.data) {
            for (const s of res.data) {
              map.set(s.id, {
                provider: s.provider,
                repository: s.repository,
                projectName: p.name,
                projectId: p.id,
              });
            }
          }
        })
      );
      return map;
    }
  );

  /* Fetch releases â€” scoped by project or aggregated across all */
  const { data: scopedData, isLoading: scopedLoading } = useSWR(
    projectFilter !== "all" ? ["releases", page, projectFilter] : null,
    () => releasesApi.listByProject(projectFilter, page)
  );

  const { data: allReleasesData, isLoading: allLoading } = useSWR(
    projectFilter === "all" && projectsData
      ? ["all-releases", page]
      : null,
    async () => {
      if (!projectsData?.data?.length) return [];
      const results = await Promise.all(
        projectsData.data.map((p: Project) =>
          releasesApi.listByProject(p.id, page).catch(() => null)
        )
      );
      return results
        .filter((r): r is NonNullable<typeof r> => r !== null)
        .flatMap((r) => r.data)
        .sort(
          (a, b) =>
            new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
        );
    }
  );

  const isLoading = projectFilter !== "all" ? scopedLoading : allLoading;

  /* Enrich releases with source metadata */
  const rawReleases: Release[] =
    projectFilter !== "all"
      ? scopedData?.data ?? []
      : allReleasesData ?? [];

  const releases: ReleaseRow[] = rawReleases.map((r) => {
    const info = sourceMap?.get(r.source_id);
    return {
      ...r,
      _projectName: info?.projectName,
      _projectId: info?.projectId,
      _provider: info?.provider,
      _repository: info?.repository,
    };
  });

  /* Pagination math */
  const total = projectFilter !== "all" ? (scopedData?.meta?.total ?? 0) : releases.length;
  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
  const startRow = (page - 1) * PER_PAGE + 1;
  const endRow = Math.min(page * PER_PAGE, total);

  return (
    <div className="space-y-6">
      {/* Page title */}
      <h1
        style={{
          fontFamily: "var(--font-fraunces)",
          fontSize: "24px",
          fontWeight: 700,
          color: "#111113",
        }}
      >
        Releases
      </h1>

      {/* Project filter */}
      <div>
        <select
          value={projectFilter}
          onChange={(e) => {
            setProjectFilter(e.target.value);
            setPage(1);
          }}
          className="appearance-none rounded-md bg-white px-3 py-2 pr-8 outline-none transition-shadow"
          style={{
            fontFamily: "var(--font-dm-sans)",
            fontSize: "13px",
            color: "#111113",
            border: "1px solid #e8e8e5",
          }}
          onFocus={(e) =>
            (e.currentTarget.style.boxShadow = "0 0 0 2px #e8601a40")
          }
          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
        >
          <option value="all">All Projects</option>
          {projectsData?.data.map((p: Project) => (
            <option key={p.id} value={p.id}>
              {p.name}
            </option>
          ))}
        </select>
      </div>

      {/* Table card */}
      <div
        className="overflow-hidden rounded-lg bg-white"
        style={{ border: "1px solid #e8e8e5" }}
      >
        {isLoading ? (
          <div
            className="py-16 text-center"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "13px",
              color: "#6b7280",
            }}
          >
            Loading...
          </div>
        ) : releases.length === 0 ? (
          <div className="py-16 text-center">
            <p
              style={{
                fontFamily: "var(--font-fraunces)",
                fontStyle: "italic",
                fontSize: "15px",
                color: "#9ca3af",
              }}
            >
              No releases ingested yet
            </p>
          </div>
        ) : (
          <table className="w-full">
            <thead>
              <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
                {["Project", "Provider", "Repository", "Version", "Released", "Age", ""].map(
                  (col) => (
                    <th
                      key={col}
                      className="px-4 py-3 text-left"
                      style={{
                        fontFamily: "var(--font-dm-sans)",
                        fontSize: "11px",
                        fontWeight: 600,
                        textTransform: "uppercase" as const,
                        letterSpacing: "0.08em",
                        color: "#9ca3af",
                      }}
                    >
                      {col}
                    </th>
                  )
                )}
              </tr>
            </thead>
            <tbody>
              {releases.map((release) => (
                <tr
                  key={release.id}
                  className="transition-colors hover:bg-[#fafaf9]"
                  style={{ borderBottom: "1px solid #e8e8e5" }}
                >
                  {/* Project */}
                  <td className="px-4 py-3">
                    {release._projectId ? (
                      <Link
                        href={`/projects/${release._projectId}`}
                        className="hover:underline"
                        style={{
                          fontFamily: "var(--font-dm-sans)",
                          fontSize: "13px",
                          color: "#111113",
                          fontWeight: 500,
                        }}
                      >
                        {release._projectName ?? "\u2014"}
                      </Link>
                    ) : (
                      <span
                        style={{
                          fontFamily: "var(--font-dm-sans)",
                          fontSize: "13px",
                          color: "#9ca3af",
                        }}
                      >
                        {"\u2014"}
                      </span>
                    )}
                  </td>

                  {/* Provider */}
                  <td className="px-4 py-3">
                    {release._provider ? (
                      <ProviderBadge provider={release._provider} />
                    ) : (
                      <span
                        style={{
                          fontFamily: "var(--font-dm-sans)",
                          fontSize: "13px",
                          color: "#9ca3af",
                        }}
                      >
                        {"\u2014"}
                      </span>
                    )}
                  </td>

                  {/* Repository */}
                  <td className="px-4 py-3">
                    <span
                      style={{
                        fontFamily: "'JetBrains Mono', monospace",
                        fontSize: "12px",
                        color: "#374151",
                      }}
                    >
                      {release._repository ?? release.source_id}
                    </span>
                  </td>

                  {/* Version */}
                  <td className="px-4 py-3">
                    <Link href={`/releases/${release.id}`}>
                      <VersionChip version={release.version} />
                    </Link>
                  </td>

                  {/* Released date */}
                  <td className="px-4 py-3">
                    <span
                      style={{
                        fontFamily: "var(--font-dm-sans)",
                        fontSize: "13px",
                        color: "#6b7280",
                      }}
                    >
                      {release.released_at
                        ? new Date(release.released_at).toLocaleDateString()
                        : "\u2014"}
                    </span>
                  </td>

                  {/* Age */}
                  <td className="px-4 py-3">
                    <span
                      style={{
                        fontFamily: "var(--font-dm-sans)",
                        fontSize: "13px",
                        color: "#9ca3af",
                      }}
                    >
                      {timeAgo(release.released_at ?? release.created_at)}
                    </span>
                  </td>

                  {/* Provider link */}
                  <td className="px-4 py-3">
                    {release._provider && release._repository && (() => {
                      const url = getProviderUrl(release._provider, release._repository, release.version);
                      return url ? (
                        <a
                          href={url}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="inline-flex items-center transition-colors hover:opacity-70"
                          style={{ color: "#9ca3af" }}
                          title="View on provider"
                        >
                          <ExternalLink size={14} />
                        </a>
                      ) : null;
                    })()}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {/* Pagination */}
      {total > 0 && (
        <div className="flex items-center justify-between">
          <span
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "13px",
              color: "#9ca3af",
            }}
          >
            {startRow}&ndash;{endRow} of {total}
          </span>
          <div className="flex items-center gap-2">
            <button
              disabled={page <= 1}
              onClick={() => setPage(page - 1)}
              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
              style={{
                fontFamily: "var(--font-dm-sans)",
                fontSize: "13px",
                color: "#374151",
                border: "1px solid #e8e8e5",
              }}
            >
              Previous
            </button>
            <button
              disabled={page >= totalPages}
              onClick={() => setPage(page + 1)}
              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
              style={{
                fontFamily: "var(--font-dm-sans)",
                fontSize: "13px",
                color: "#374151",
                border: "1px solid #e8e8e5",
              }}
            >
              Next
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

